void run_all_reachability_tests() {
    run_test_batch_0_to_100();
    run_test_batch_100_to_200();
    run_test_batch_200_to_300();
    run_test_batch_300_to_400();
    run_test_batch_400_to_500();
    run_test_batch_500_to_600();
    run_test_batch_600_to_700();
    run_test_batch_700_to_800();
    run_test_batch_800_to_900();
    run_test_batch_900_to_1000();
}

int main() {
    std::cout << "==================================================\n";
    std::cout << "PHASR Phase-2: Hierarchy Reachability Engine Suite\n";
    std::cout << "Target Engine: " << ENGINE_TYPE << "\n";
    std::cout << "==================================================\n\n";

    std::cout << "[1/2] Running " << NUM_TESTS << " Adjacency Matrix Assertions...\n";
    run_all_reachability_tests();
    std::cout << "      Assertions Run: " << g_stats.total << "\n";
    std::cout << "      Passed: " << g_stats.passed << " | Failed: " << g_stats.failed << "\n";
    
    if (g_stats.failed == 0) {
        std::cout << "      SUCCESS: All reachability matrices and assembly helpers verified successfully.\n\n";
    } else {
        std::cout << "      WARNING: Validator failures detected in reachability computation!\n\n";
    }

    std::cout << "[2/2] Running Damped Wave Privilege Verification Simulation...\n";
    std::cout << "      Equation: d^2(phi)/dt^2 + gamma * d(phi)/dt - v^2 * del^2(phi) = 0\n\n";

    WaveSim sim;
    init_wave_sim(&sim);

    // Test Telemetry Edge cases: zero or negative dt
    std::cout << "  --- Telemetry Wave Edge Cases Assertions ---\n";
    step_wave_sim(&sim, 0.0f);
    step_wave_sim(&sim, -0.5f);
    std::cout << "  --------------------------------------------\n\n";

    float dt = 0.1f;
    for (int step = 0; step < 30; step++) {
        step_wave_sim(&sim, dt);
        if (step % 3 == 0) {
            print_wave_profile(&sim);
            std::cout << "\n";
        }
    }

    std::cout << "Wave simulation telemetry sequence complete.\n";
    std::cout << "==================================================\n";
    return g_stats.failed == 0 ? 0 : 1;
}
